export class NotificationBellComponent{constructor(options={}){this.storageKey=options.storageKey||'sadec-notifications';this.panel=null;this.bell=null;this.badge=null;this.notifications=[];this.defaultNotifications=options.defaultNotifications||[];}init(panelComponent){this.panel=panelComponent;this.loadNotifications();this.createBell();this.bindEvents();this.updateBadge();this.requestNotificationPermission();}loadNotifications(){const stored=localStorage.getItem(this.storageKey);if(stored){this.notifications=JSON.parse(stored);}else{this.notifications=[...this.defaultNotifications];this.save();}}save(){localStorage.setItem(this.storageKey,JSON.stringify(this.notifications));}createBell(){const bell=document.createElement('button');bell.id='notification-bell';bell.className='notification-bell';bell.setAttribute('aria-label','Notifications');bell.innerHTML=`<span class="material-symbols-outlined">notifications</span><span class="notification-badge" style="display: none;">0</span>`;const header=document.querySelector('.header-section,.top-bar,.page-header');if(header){const actionsContainer=header.querySelector('.flex,.header-actions');if(actionsContainer){actionsContainer.insertBefore(bell,actionsContainer.firstChild);}}this.bell=bell;this.badge=bell.querySelector('.notification-badge');}bindEvents(){this.bell.addEventListener('click',(e)=>{e.stopPropagation();this.togglePanel();});document.addEventListener('click',(e)=>{if(this.panel&&!this.panel.contains(e.target)&&!this.bell.contains(e.target)){this.closePanel();}});document.addEventListener('keydown',(e)=>{if(e.key==='Escape'&&this.panel.classList.contains('open')){this.closePanel();}});}togglePanel(){const isOpen=this.panel.classList.contains('open');if(isOpen){this.closePanel();}else{this.openPanel();}}openPanel(){this.panel.renderNotifications(this.notifications);this.panel.classList.add('open');document.body.style.overflow='hidden';}closePanel(){this.panel.classList.remove('open');document.body.style.overflow='';}updateBadge(){const unreadCount=this.notifications.filter(n=>!n.read).length;if(unreadCount>0){this.badge.style.display='flex';this.badge.textContent=unreadCount>99 ? '99+' : unreadCount;this.bell.classList.add('has-notifications');}else{this.badge.style.display='none';this.bell.classList.remove('has-notifications');}}markAsRead(id){const notif=this.notifications.find(n=>n.id===id);if(notif){notif.read=true;this.save();this.updateBadge();this.panel.renderNotifications(this.notifications);}}markAllAsRead(){this.notifications.forEach(n=>{n.read=true;});this.save();this.updateBadge();this.panel.renderNotifications(this.notifications);}addNotification(notif){const newNotif={id: Date.now().toString(),title: notif.title,message: notif.message,icon: notif.icon||'notifications',time: Date.now(),read: false,type: notif.type||'info',...notif};this.notifications.unshift(newNotif);this.save();this.updateBadge();if(Notification.permission==='granted'){this.showBrowserNotification(newNotif);}if(this.panel.classList.contains('open')){this.panel.renderNotifications(this.notifications);}return newNotif;}showBrowserNotification(notif){new Notification(notif.title,{body: notif.message,icon: '/favicon.png',badge: '/favicon.png',tag: notif.id,requireInteraction: false});}requestNotificationPermission(){if('Notification' in window&&Notification.permission==='default'){document.body.addEventListener('click',()=>{Notification.requestPermission();},{once: true});}}timeAgo(timestamp){const seconds=Math.floor((Date.now()-timestamp)/1000);if(seconds<60)return 'Vừa xong';if(seconds<3600)return `${Math.floor(seconds/60)}phút trước`;if(seconds<86400)return `${Math.floor(seconds/3600)}giờ trước`;if(seconds<604800)return `${Math.floor(seconds/86400)}ngày trước`;return new Date(timestamp).toLocaleDateString('vi-VN');}}